var selectedRow = null;
var rows = document.querySelectorAll(".nhsuk-table__body tr");
rows.forEach((row) => {
  row.addEventListener("click", () => {
    if (selectedRow === row) {
      row.classList.remove("selected");
      selectedRow = null;
      return;
    }
    if (selectedRow) {
      selectedRow.classList.remove("selected");
    }
    row.classList.add("selected");
    selectedRow = row;
  });
});
